import React from 'react';
import { useParams, useNavigate } from 'react-router-dom';

// 案例详情数据（建议从API获取或与HomePage共享）
const caseDetails = {
  1: {
    title: "Too Good to Be True? It Was.",
    image: "/images/homepage/case1.jpg",
    description: "A student received an email claiming they won a free iPhone. After clicking the link and entering personal details, their social media accounts were hacked.",
    lessons: [
      "Never trust unsolicited prize notifications",
      "Check sender email addresses carefully",
      "Look for poor grammar in messages"
    ]
  },
  2: {
    title: "Oops… That Wasn't What I Thought!",
    image: "/images/homepage/case2.jpg",
    description: "A fake game mod installation secretly installed malware that stole saved passwords from the victim's browser.",
    lessons: [
      "Only download software from official stores",
      "Read installation prompts carefully",
      "Use separate passwords for different accounts"
    ]
  },
  // 其他案例...
};

export default function CaseDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const currentCase = caseDetails[id] || caseDetails[1]; // 默认展示第一个案例

  return (
    <div className="content-card"> {/* 使用全局样式类 */}
      <div style={styles.container}>
        <button 
          onClick={() => navigate(-1)} 
          style={styles.backButton}
        >
          ← Back to Cases
        </button>

        <h2 style={styles.title}>{currentCase.title}</h2>
        
        <div style={styles.imageContainer}>
          <img 
            src={currentCase.image} 
            alt={currentCase.title} 
            style={styles.image}
            loading="lazy"
          />
        </div>

        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>📌 What Happened</h3>
          <p style={styles.description}>{currentCase.description}</p>
        </div>

        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>🔍 Key Lessons</h3>
          <ul style={styles.lessonsList}>
            {currentCase.lessons.map((lesson, index) => (
              <li key={index} style={styles.lessonItem}>
                <span style={styles.bullet}>•</span> {lesson}
              </li>
            ))}
          </ul>
        </div>

        <div style={styles.navigation}>
          <button 
            onClick={() => navigate(`/home/case/${parseInt(id) - 1}`)} 
            disabled={parseInt(id) <= 1}
            style={styles.navButton}
          >
            Previous Case
          </button>
          <button 
            onClick={() => navigate(`/home/case/${parseInt(id) + 1}`)} 
            disabled={parseInt(id) >= Object.keys(caseDetails).length}
            style={styles.navButton}
          >
            Next Case
          </button>
        </div>
      </div>
    </div>
  );
}

const styles = {
  container: {
    padding: '1.5em',
    maxWidth: '800px',
    margin: '0 auto',
  },
  backButton: {
    background: 'none',
    border: 'none',
    color: '#0288d1',
    cursor: 'pointer',
    fontSize: '1em',
    marginBottom: '1.5em',
    padding: '0.5em 1em',
    borderRadius: '6px',
    transition: 'all 0.2s',
    ':hover': {
      backgroundColor: '#e1f5fe'
    }
  },
  title: {
    color: '#00796b',
    fontSize: '1.8em',
    marginBottom: '1em',
    textAlign: 'center'
  },
  imageContainer: {
    margin: '1.5em 0',
    textAlign: 'center'
  },
  image: {
    maxWidth: '100%',
    borderRadius: '10px',
    boxShadow: '0 4px 12px rgba(0,0,0,0.1)',
    border: '2px solid #b2ebf2'
  },
  section: {
    margin: '2em 0'
  },
  sectionTitle: {
    color: '#0288d1',
    fontSize: '1.3em',
    marginBottom: '0.8em',
    borderBottom: '2px solid #b2ebf2',
    paddingBottom: '0.3em'
  },
  description: {
    lineHeight: '1.6',
    fontSize: '1.1em',
    color: '#333'
  },
  lessonsList: {
    paddingLeft: '1.5em'
  },
  lessonItem: {
    margin: '0.8em 0',
    lineHeight: '1.5',
    display: 'flex',
    alignItems: 'flex-start'
  },
  bullet: {
    color: '#0288d1',
    marginRight: '0.5em',
    fontSize: '1.2em'
  },
  navigation: {
    display: 'flex',
    justifyContent: 'space-between',
    marginTop: '2em'
  },
  navButton: {
    backgroundColor: '#4fb3bf',
    color: 'white',
    border: 'none',
    padding: '0.8em 1.5em',
    borderRadius: '6px',
    cursor: 'pointer',
    fontSize: '1em',
    transition: 'all 0.2s',
    ':hover': {
      backgroundColor: '#00838f'
    },
    ':disabled': {
      backgroundColor: '#bdbdbd',
      cursor: 'not-allowed'
    }
  }
};
